use std::io::{self, Read};
fn valid(b: &Vec<Vec<char>>, r: usize, c: usize, ch: char) -> bool { for i in 0..9 { if b[r][i] == ch || b[i][c] == ch { return false; } } let br = (r / 3) * 3; let bc = (c / 3) * 3; for i in br..br+3 { for j in bc..bc+3 { if b[i][j] == ch { return false; } } } true }
fn solve(b: &mut Vec<Vec<char>>) -> bool { for r in 0..9 { for c in 0..9 { if b[r][c] == '.' { for ch in '1'..='9' { if valid(b,r,c,ch) { b[r][c] = ch; if solve(b) { return true; } b[r][c] = '.'; } } return false; } } } true }
fn main(){ let mut input=String::new(); io::stdin().read_to_string(&mut input).unwrap(); if input.is_empty(){return;} let lines: Vec<&str>=input.split('\n').map(|s|s.trim_end_matches('\r')).collect(); let mut idx=0usize; let t: usize=lines[idx].trim().parse().unwrap_or(0); idx+=1; let mut out=Vec::new(); for _ in 0..t { let mut b=Vec::new(); for _ in 0..9 { b.push(lines.get(idx).copied().unwrap_or("").chars().collect::<Vec<char>>()); idx += 1; } solve(&mut b); for row in b { out.push(row.iter().collect::<String>()); } } print!("{}", out.join("\n")); }
